import React, { useState, useRef } from 'react';
import api from '../api/api';
import {
    FaUpload,
    FaCamera,
    FaSpinner,
    FaCheckCircle,
    FaTimesCircle,
    FaChartPie,
    FaChartBar
} from 'react-icons/fa';

const CalorieUpload = ({ profile, fetchNutrientWarnings }) => {

    const fileInputRef = useRef(null);

    const [mealType, setMealType] = useState('');
    const [uploadedFile, setUploadedFile] = useState(null);
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [uploadMessage, setUploadMessage] = useState('');

    // ===============================
    // DAILY MACRO TARGET CALCULATION
    // ===============================
    const calculateDailyTargets = (dailyCalorieTarget, goal) => {
        const target = Number(dailyCalorieTarget);
        if (!target || target === 0) return { protein: 0, fat: 0, carbs: 0 };

        let proteinPercent, fatPercent, carbPercent;

        switch (goal) {
            case 'lose':
                proteinPercent = 0.45;
                fatPercent = 0.30;
                carbPercent = 0.25;
                break;
            case 'gain':
                proteinPercent = 0.35;
                fatPercent = 0.30;
                carbPercent = 0.35;
                break;
            case 'maintain':
            default:
                proteinPercent = 0.40;
                fatPercent = 0.30;
                carbPercent = 0.30;
        }

        return {
            protein: Math.round((target * proteinPercent) / 4),
            fat: Math.round((target * fatPercent) / 9),
            carbs: Math.round((target * carbPercent) / 4),
        };
    };

    const dailyTargets = calculateDailyTargets(profile.dailyCalorieTarget, profile.goal);

    // ===============================
    // FILE HANDLING
    // ===============================
    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setUploadedFile(file);
            setUploadError('');
            setPrediction(null);
            setUploadMessage('');
        }
    };

    const handleSimulateUploadClick = () => {
        if (!mealType) {
            setUploadError("Please select a Meal Type before selecting an image.");
            return;
        }
        fileInputRef.current?.click();
    };

    // ===============================
    // SUBMIT (REAL IMAGE UPLOAD)
    // ===============================
    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setUploadError('');
        setUploadMessage('');
        setPrediction(null);

        if (!mealType) {
            setUploadError("Please select a Meal Type.");
            setLoading(false);
            return;
        }

        if (!uploadedFile) {
            setUploadError("Please select an image file.");
            setLoading(false);
            return;
        }

        try {
            const formData = new FormData();
            formData.append("file", uploadedFile);
            formData.append("mealType", mealType);

            const response = await api.post(
                "http://localhost:5001/predict-calories-image",
                formData,
                {
                    headers: {
                        "Content-Type": "multipart/form-data",
                    },
                }
            );

            setPrediction(response.data.prediction);
            setUploadMessage("Meal analyzed successfully!");

            if (fetchNutrientWarnings) {
                await fetchNutrientWarnings();
            }

        } catch (err) {
            console.error(err);
            setUploadError("Image analysis failed. Ensure FastAPI is running on port 5001.");
        } finally {
            setLoading(false);
            setUploadedFile(null);
        }
    };

    const isReadyToEstimate = mealType && uploadedFile;

    // ===============================
    // MACRO PIE STYLE
    // ===============================
    const getMacroConicStyle = () => {
        const macro = prediction?.macroBreakdown;
        if (!macro) return { background: 'conic-gradient(#333 0deg)' };

        const total = macro.protein + macro.fat + macro.carbohydrates;
        if (!total) return { background: 'conic-gradient(#333 0deg)' };

        const pEnd = (macro.protein / total) * 360;
        const fEnd = pEnd + (macro.fat / total) * 360;

        return {
            background: `conic-gradient(
                #ef4444 0deg ${pEnd}deg,
                #f59e0b ${pEnd}deg ${fEnd}deg,
                #3b82f6 ${fEnd}deg 360deg
            )`,
        };
    };

    return (
        <div className="space-y-6">

            <div className="bg-[#161B22] p-6 rounded-xl border border-[#2D333B] shadow-lg">
                <form onSubmit={handleSubmit} className="space-y-4">

                    {/* MEAL TYPE */}
                    <select
                        value={mealType}
                        onChange={(e) => {
                            setMealType(e.target.value);
                            setUploadedFile(null);
                        }}
                        className="select"
                    >
                        <option value="">-- Select Meal Type --</option>
                        <option value="Breakfast">Breakfast</option>
                        <option value="Lunch">Lunch</option>
                        <option value="Dinner">Dinner</option>
                        <option value="Snack">Snack</option>
                    </select>

                    {/* HIDDEN FILE INPUT */}
                    <input
                        type="file"
                        ref={fileInputRef}
                        accept="image/*"
                        style={{ display: 'none' }}
                        onChange={handleFileChange}
                    />

                    {/* FILE PICKER UI */}
                    <div className="text-center p-6 border-2 border-dashed border-gray-700 rounded-lg">
                        {uploadedFile ? (
                            <>
                                <FaCheckCircle className="mx-auto text-4xl text-green-400 mb-2" />
                                <p className="text-sm text-green-400">{uploadedFile.name}</p>
                                <button type="button" onClick={() => setUploadedFile(null)} className="text-red-400 text-xs mt-2">
                                    <FaTimesCircle className="inline mr-1" /> Remove
                                </button>
                            </>
                        ) : (
                            <>
                                <FaCamera className="mx-auto text-4xl text-gray-500 mb-2" />
                                <button
                                    type="button"
                                    onClick={handleSimulateUploadClick}
                                    disabled={!mealType}
                                    className="bg-blue-500 text-white px-4 py-2 rounded"
                                >
                                    Select Image
                                </button>
                            </>
                        )}
                    </div>

                    {/* SUBMIT */}
                    <button
                        type="submit"
                        disabled={!isReadyToEstimate || loading}
                        className="w-full bg-green-500 text-white py-3 rounded flex justify-center items-center"
                    >
                        {loading ? <FaSpinner className="animate-spin mr-2" /> : <FaUpload className="mr-2" />}
                        {loading ? "Analyzing..." : "Estimate & Log Meal"}
                    </button>

                    {uploadError && <p className="text-red-400">{uploadError}</p>}
                    {uploadMessage && <p className="text-green-400">{uploadMessage}</p>}
                </form>
            </div>

            {/* RESULTS */}
            {prediction && (
                <div className="p-4 border border-gray-700 rounded-xl bg-[#1E1E1E] space-y-4">
                    <h4 className="text-xl font-bold text-yellow-400">Estimation Result</h4>

                    <p><b>Food:</b> {prediction.foodName}</p>
                    <p><b>Calories:</b> {prediction.caloriesEstimated} kcal</p>

                    <div className="flex items-center space-x-6">
                        <div className="h-24 w-24 rounded-full" style={getMacroConicStyle()}></div>
                        <div>
                            <p>Protein: {prediction.macroBreakdown.protein}g</p>
                            <p>Fat: {prediction.macroBreakdown.fat}g</p>
                            <p>Carbs: {prediction.macroBreakdown.carbohydrates}g</p>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CalorieUpload;
